{
  "plan": [
    {
      "tool": "iam.check_permission",
      "arguments": {
        "action": "incident.create",
        "resource": "incident-response",
        "context": "Validating permissions before initiating incident response workflow"
      },
      "depends_on": []
    },
    {
      "tool": "datadog.list_alerts",
      "arguments": {
        "filter": {
          "status": "triggered",
          "priority": ["P1", "P2"]
        },
        "limit": 10
      },
      "depends_on": [1]
    },
    {
      "tool": "datadog.query_metric",
      "arguments": {
        "query": "avg:aws.cloudwatch.metric{*} by {service,environment}",
        "from": "now-1h",
        "to": "now",
        "context": {
          "alert_ids": "$2.alert_ids",
          "affected_services": "$2.affected_services"
        }
      },
      "depends_on": [2]
    },
    {
      "tool": "sql.postgres.query",
      "arguments": {
        "query": "SELECT al.service_name, al.error_code, al.log_level, al.message, al.timestamp FROM access_log_facts al WHERE al.timestamp >= NOW() - INTERVAL '1 hour' AND al.log_level IN ('ERROR', 'CRITICAL') ORDER BY al.timestamp DESC LIMIT 100",
        "database": "entbench_warehouse"
      },
      "depends_on": [3]
    },
    {
      "tool": "file.read",
      "arguments": {
        "path": "s3://incident-logs/cloudwatch-exports/",
        "filter": {
          "time_range_start": "now-1h",
          "time_range_end": "now",
          "service_context": "$3.affected_services",
          "log_levels": ["ERROR", "CRITICAL", "FATAL"]
        },
        "format": "json"
      },
      "depends_on": [3]
    },
    {
      "tool": "mongo.find",
      "arguments": {
        "collection": "incident_history",
        "filter": {
          "service": "$3.affected_services",
          "resolved": false,
          "created_at": { "$gte": "now-7d" }
        },
        "projection": {
          "incident_id": 1,
          "severity": 1,
          "root_cause": 1,
          "resolution_steps": 1
        },
        "limit": 5
      },
      "depends_on": [3]
    },
    {
      "tool": "pagerduty.create_incident",
      "arguments": {
        "title": "Incident: Elevated Errors Detected in $3.affected_services",
        "severity": "high",
        "body": {
          "type": "incident_body",
          "details": "CloudWatch alerts triggered. Metrics anomaly detected. Affected services: $3.affected_services. Alert count: $2.total_alerts. Top error from warehouse logs: $4.results[
